solutions.javascript:
// Solution
function validate_ref_name(ref_name) {
  // Check if the input string is not empty
  if (ref_name.length === 0) {
    return false;
  }

  // Check if the input string starts with a hyphen
  if (ref_name[0] === '-') {
    return false;
  }

  // Check if the input string contains any non-ASCII characters
  if (/^[a-zA-Z0-9-]+$/.test(ref_name)) {
    return true;
  }

  // If any of the checks fail, return false
  return false;
}

solutions.python:
class Solution:
  def validate_ref_name(self, ref_name: str) -> bool:
    # Check if the input string is not empty
    if not ref_name:
      return False

    # Check if the input string starts with a hyphen
    if ref_name[0] == '-':
      return False

    # Check if the input string contains only ASCII letters, digits, and hyphens
    if ref_name.isascii() and ref_name.replace('-', '').isalnum():
      return True

    # If any of the checks fail, return False
    return False
